import { VocabItem } from '../types';
import { ADVANCED_VOCAB } from './vocab_advanced';
import { ADVANCED_VOCAB_DETAILS_1 } from './vocab_advanced_details_1';
import { ADVANCED_VOCAB_DETAILS_2 } from './vocab_advanced_details_2';
import { ADVANCED_VOCAB_DETAILS_3 } from './vocab_advanced_details_3';


const createVocab = (idBase: string, cat: string, list: [string, string][]): VocabItem[] => {
  return list.map((item, idx) => ({
    id: `${idBase}-${idx}`,
    english: item[0],
    indonesian: item[1],
    category: cat,
    isUserGenerated: false
  }));
};

